beforeSaveCustomScript:
$desId = entity\attribute('cDesignationId');
$deptId = record\attribute('CDesignation', $desId, 'departmentId');

entity\setAttribute('cDepartmentId', $deptId);
$employeeId = entity\attribute('cEmployeeId');

record\update('CEmployee', $employeeId, 
    'isActive', entity\attribute('isActive'), 
    'isIntern', entity\attribute('cIsIntern'),
    'isFNF', entity\attribute('cIsFNF'),
    'name', string\concatenate(entity\attribute('firstName'),' ', entity\attribute('middleName'),' ', entity\attribute('lastName'))
);
